import { mergeProps, splitProps } from "solid-js"

import { cn } from "@/lib/utils"

type AvatarRootProps<T extends ValidComponent = "span"> = PolymorphicProps<
  T,
  ImagePrimitive.ImageRootProps<T>
> &
